# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
from web3 import Web3
import json

app = Flask(__name__)

# Initialize Web3 connection
w3 = Web3(Web3.HTTPProvider('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'))

@app.route('/authenticate', methods=['POST'])
def authenticate():
    try:
        data = request.get_json()
        
        if not data or 'message' not in data or 'signature' not in data:
            return jsonify({'error': 'Missing message or signature'}), 400
            
        message = data['message']
        signature = data['signature']
        
        # Recover the address from the signature
        recovered_address = w3.eth.account.recover_message(message, signature=signature)
        
        # Return the recovered address
        return jsonify({'address': recovered_address}), 200
        
    except Exception as e:
        return jsonify({'error': str(e)}), 400

@app.route('/verify', methods=['POST'])
def verify():
    try:
        data = request.get_json()
        
        if not data or 'message' not in data or 'signature' not in data or 'expected_address' not in data:
            return jsonify({'error': 'Missing message, signature, or expected_address'}), 400
            
        message = data['message']
        signature = data['signature']
        expected_address = data['expected_address']
        
        # Recover the address from the signature
        recovered_address = w3.eth.account.recover_message(message, signature=signature)
        
        # Verify if recovered address matches expected address
        if recovered_address.lower() == expected_address.lower():
            return jsonify({'valid': True, 'address': recovered_address}), 200
        else:
            return jsonify({'valid': False}), 401
            
    except Exception as e:
        return jsonify({'error': str(e)}), 400

if __name__ == '__main__':
    app.run(debug=True)